class Solution:
    def powerfulIntegers(self, x: int, y: int, bound: int) -> List[int]:
        res = set()
        for i in range(20):
            for j in range(20):
                v = x**i + y**j
                if v <= bound:
                    res.add(v)
        return sorted(list(res))
